def isEmpty(queue):
    return len(queue) == 0

def enqueue(queue, element):
    queue.append(element)
    print(element, 'added to queue')

def dequeue(queue):
    if isEmpty(queue):
        print('Queue Underflow! Queue is empty.')
        return None
    return queue.pop(0)

def peek(queue):
    if isEmpty(queue):
        print('Queue is empty.')
        return None
    return queue[0]

def display(queue):
    if isEmpty(queue):
        print('Queue is empty.')
    else:
        print('Queue (front to rear):')
        for element in queue:
            print(element, end=' ')
        print()

# Main program
queue = []
enqueue(queue, 10)
enqueue(queue, 20)
enqueue(queue, 30)
display(queue)
print('Front element:', peek(queue))
print('Dequeued:', dequeue(queue))
display(queue)

def isEmpty(deque):
    return len(deque) == 0

def add_front(deque, element):
    deque.insert(0, element)
    print(element, 'added at front')

def add_rear(deque, element):
    deque.append(element)
    print(element, 'added at rear')

def remove_front(deque):
    if isEmpty(deque):
        print('Deque Underflow! Deque is empty.')
        return None
    return deque.pop(0)

def remove_rear(deque):
    if isEmpty(deque):
        print('Deque Underflow! Deque is empty.')
        return None
    return deque.pop()

def display(deque):
    if isEmpty(deque):
        print('Deque is empty.')
    else:
        print('Deque (front to rear):', deque)

# Main program
dq = []
add_rear(dq, 10)
add_rear(dq, 20)
add_front(dq, 5)
display(dq)  # [5, 10, 20]
print('Removed from front:', remove_front(dq))
print('Removed from rear:', remove_rear(dq))
display(dq)  # [10]

queue = []

def enqueue_order():
    order_no = int(input('Enter order number: '))
    item = input('Enter item name: ')
    order = {'order_no': order_no, 'item': item}
    queue.append(order)
    print('Order', order_no, 'added to queue.')

def dequeue_order():
    if len(queue) == 0:
        print('No orders in the queue!')
    else:
        order = queue.pop(0)
        print('Processing Order', order['order_no'], '- Item:', order['item'])

def display_orders():
    if len(queue) == 0:
        print('No orders in the queue.')
    else:
        print('Pending Orders (front to rear):')
        for order in queue:
            print('Order No:', order['order_no'], '| Item:', order['item'])

# Menu-driven program
while True:
    print('\n--- Restaurant Order Queue ---')
    print('1. Add new order')
    print('2. Process next order')
    print('3. Display all orders')
    print('4. Exit')
    choice = int(input('Enter your choice: '))
    if choice == 1:
        enqueue_order()
    elif choice == 2:
        dequeue_order()
    elif choice == 3:
        display_orders()
    elif choice == 4:
        print('Exiting program.')
        break
    else:
        print('Invalid choice!')
